mapper.select:
SELECT ranked.id, ranked.enterprise_id, ranked.resume_id, ranked.student_id, ranked.tags, ranked.rating, ranked.notes, ranked.status, ranked.created_time, ranked.updated_time FROM ( SELECT tf.id, tf.enterprise_id, tf.resume_id, tf.student_id, tf.tags, tf.rating, tf.notes, tf.status, tf.created_time, tf.updated_time, ROW_NUMBER() OVER ( PARTITION BY CONCAT( CASE WHEN tf.student_id IS NULL THEN 'R:' ELSE 'S:' END, CAST(COALESCE(tf.student_id, tf.resume_id) AS CHAR) ) ORDER BY tf.updated_time DESC, tf.created_time DESC, tf.id DESC ) AS rn FROM talent_favorite tf WHERE tf.enterprise_id = #{enterpriseId}
AND tf.status = #{status}
AND CAST(tf.tags AS CHAR) LIKE CONCAT('%', #{tagName}, '%')
AND ( CAST(tf.resume_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') OR CAST(tf.student_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') OR tf.notes LIKE CONCAT('%', #{keyword}, '%') OR CAST(tf.tags AS CHAR) LIKE CONCAT('%', #{keyword}, '%') )
) ranked WHERE ranked.rn = 1 ORDER BY ranked.updated_time DESC, ranked.id DESC

SELECT *
FROM talent_favorite
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
LIMIT 1

SELECT COUNT(1)
FROM talent_favorite
WHERE enterprise_id = #{enterpriseId}
  AND student_id = #{studentId}

mapper.update:
UPDATE talent_favorite
SET tags = #{tags},
    rating = #{rating},
    notes = #{notes},
    updated_time = #{updatedTime}
WHERE id = #{id}
  AND enterprise_id = #{enterpriseId}

UPDATE talent_favorite
SET status = #{status},
    updated_time = #{updatedTime}
WHERE id = #{id}
  AND enterprise_id = #{enterpriseId}

mapper.delete:
DELETE
FROM talent_favorite
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}

